class Solution:
    def makeTheIntegerZero(self, num1: int, num2: int) -> int:
        if num2 == 0:
            return 0 if num1 == 0 else -1
        if num1 % num2 == 0:
            return abs(num1 // num2)
        if num1 % (2 * num2) == 0:
            return abs(num1 // (2 * num2)) * 2
        if num1 % (4 * num2) == 0:
            return abs(num1 // (4 * num2)) * 3
        return -1
